function nextRand(e){return(1103515245*e+12345)%(1<<31)}function genPerm(e,t){for(var n=[...Array(e).keys()],o=0;o<e;++o){var r=(t=nextRand(t))%(e-o)+o,a=n[o];n[o]=n[r],n[r]=a}return n}function base64Encode(e){return window.btoa(e)}function base64Decode(e){return window.atob(e)}function FYForward(e,t){for(var n=base64Encode(e),o=(n=n.replace(/=+$/,"")).length,r=genPerm(o,t),a="",c=0;c<o;++c)a+=n[r[c]];return a}function FYBackward(e,t){for(var n=e.length,o=genPerm(n,t),r=[],a=0;a<n;++a)r[o[a]]=e[a];return base64Decode(r.join(""))}function mailtoClass(e,t){e="."+e;const n=document.querySelectorAll(e);Array.prototype.forEach.call(n,function(e){const n=FYBackward(e.dataset.content,t),o=document.createElement("a"),r=[],a=encodeURIComponent;for(const t of["cc","bcc","subject","body"])if(t in e.dataset)if("c"===t[t.length-1])for(const n of e.dataset[t].split(","))r.push(`${t}=${a(n)}`);else r.push(`${t}=${a(e.dataset[t])}`);let c="";if(r.length>0){c="?"+r.shift();for(const e of r)c+="&"+e}o.href="mailto:"+n+c,o.text=n,e.parentNode.replaceChild(o,e)})}function unscrambleClass(e,t){e="."+e;const n=document.querySelectorAll(e);Array.prototype.forEach.call(n,function(e){const n=FYBackward(e.dataset.content,t);e.insertAdjacentHTML("beforebegin",n),e.parentNode.removeChild(e)})}function scrambleClass(e,t){e="."+e;const n=document.querySelectorAll(e);Array.prototype.forEach.call(n,function(e){const n=FYForward(e.dataset.content,t);e.insertAdjacentHTML("beforebegin",n),e.parentNode.removeChild(e)})}